                                        <button onClick={() => setQuantityUnit('boxes')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${quantityUnit === 'boxes' ? 'bg-gray-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}>{t('unit_boxes_short')}</button>
                                        <button onClick={() => setQuantityUnit('pallet')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${quantityUnit === 'pallet' ? 'bg-gray-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}>{t('unit_pallet_short')}</button>
                                    </div>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-sm font-bold mb-2 uppercase tracking-wide">{t('priority_label')}</label>
                                <div className="flex bg-gray-700 rounded-lg p-1 border border-gray-600">
                                    <button onClick={() => setPriority('LOW')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${priority === 'LOW' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}>{t('prio_low')}</button>
                                    <button onClick={() => setPriority('NORMAL')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${priority === 'NORMAL' ? 'bg-green-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}>{t('prio_normal')}</button>
                                    <button onClick={() => setPriority('URGENT')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${priority === 'URGENT' ? 'bg-red-600 text-white shadow-md animate-pulse' : 'text-gray-400 hover:text-white'}`}>{t('prio_urgent')}</button>
                                </div>
                            </div>
                            <div className="flex flex-col sm:flex-row gap-4 pt-4">
                                <button onClick={handleSendToTasks} className={`w-full text-white font-bold py-4 px-6 rounded-xl shadow-lg transform transition-all duration-150 active:scale-95 flex items-center justify-center gap-2 ${entryMode === 'production' ? 'bg-teal-600 hover:bg-teal-500 shadow-[0_0_15px_rgba(13,148,136,0.4)]' : 'bg-sky-600 hover:bg-sky-500 shadow-[0_0_15px_rgba(14,165,233,0.4)]'}`}>
                                    <PlusIcon className="w-6 h-6" />
                                    {t('send_btn')}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
          )}

          {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
            <div className="animate-fade-in pb-20">
              <div className="mb-4 flex justify-center">
                  <input type="text" value={taskSearchQuery} onChange={e => setTaskSearchQuery(e.target.value)} className="w-full max-w-md px-4 py-2.5 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 placeholder:font-mono focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase" placeholder={t('task_search_placeholder')} />
              </div>
              <TaskList currentUser={currentUserRole} currentUserName={currentUser} tasks={tasks.filter(t => { const q = taskSearchQuery.toLowerCase(); return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); })} onToggleTask={onToggleTask} onEditTask={onEditTask} onDeleteTask={onDeleteTask} onToggleMissing={onToggleMissing} onSetInProgress={onSetInProgress} onToggleBlock={onToggleBlock} onToggleManualBlock={onToggleManualBlock} onMarkAsIncorrect={onMarkAsIncorrect} onAddNote={onAddNote} onReleaseTask={onReleaseTask} onAuditPart={handleAuditClick} missingReasons={missingReasons} hasPermission={hasPermission} />
            </div>
          )}

          {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && <AnalyticsTab tasks={tasks} onFetchArchivedTasks={props.onFetchArchivedTasks} systemBreaks={props.systemBreaks} />}
          {activeTab === 'settings' && hasPermission('perm_tab_settings') && <SettingsTab currentUserRole={currentUserRole} users={users} onAddUser={props.onAddUser} onUpdatePassword={props.onUpdatePassword} onUpdateUserRole={props.onUpdateUserRole} onDeleteUser={props.onDeleteUser} parts={parts} workplaces={workplaces} missingReasons={missingReasons} onAddPart={props.onAddPart} onBatchAddParts={props.onBatchAddParts} onDeletePart={props.onDeletePart} onDeleteAllParts={props.onDeleteAllParts} onAddWorkplace={props.onAddWorkplace} onBatchAddWorkplaces={props.onBatchAddWorkplaces} onDeleteWorkplace={props.onDeleteWorkplace} onDeleteAllWorkplaces={props.onDeleteAllWorkplaces} onAddMissingReason={props.onAddMissingReason} onDeleteMissingReason={props.onDeleteMissingReason} logisticsOperations={logisticsOperationsList} onAddLogisticsOperation={props.onAddLogisticsOperation} onDeleteLogisticsOperation={props.onDeleteLogisticsOperation} partRequests={props.partRequests} onApprovePartRequest={onApprovePartRequest} onRejectPartRequest={onRejectPartRequest} onArchiveTasks={onArchiveTasks} breakSchedules={breakSchedules} onAddBreakSchedule={props.onAddBreakSchedule} onDeleteBreakSchedule={props.onDeleteBreakSchedule} bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={props.onAddBOMItem} onBatchAddBOMItems={props.onBatchAddBOMItems} onDeleteBOMItem={props.onDeleteBOMItem} onDeleteAllBOMItems={props.onDeleteAllBOMItems} onApproveBOMRequest={onApproveBOMRequest} onRejectBOMRequest={id => props.onRejectBOMRequest(id)} roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} installPrompt={installPrompt} onInstallApp={onInstallApp} systemConfig={systemConfig} onUpdateSystemConfig={onUpdateSystemConfig} dbLoadWarning={dbLoadWarning} />}

          {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
              <div className="h-full animate-fade-in pb-20">
                  <div className="max-w-7xl mx-auto">
                      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

                          <div className="lg:col-span-4 space-y-6">
                              <div className="bg-gray-800 p-6 rounded-2xl shadow-xl border border-gray-700">
                                  <div className="flex items-center gap-3 mb-6">
                                      <div className="p-2 bg-teal-500/20 rounded-lg">
                                          <ClipboardListIcon className="w-6 h-6 text-teal-400" />
                                      </div>
                                      <h2 className="text-xl font-bold text-white">{t('bom_title')}</h2>
                                  </div>

                                  <div className="space-y-4">
                                      <div>
                                          <label className="block text-gray-400 text-xs font-bold mb-2 uppercase tracking-wider">{t('bom_parent')}</label>
                                          <PartNumberInput 
                                              parts={parts.map(p => p.value)} 
                                              value={bomParentQuery} 
                                              onInputChange={(val) => setBomParentQuery(val)} 
                                              onPartSelect={(val) => { if (val) setBomParentQuery(val); }} 
                                              placeholder={t('part_placeholder')} 
                                          />
                                      </div>
                                      <div>
                                          <label className="block text-gray-400 text-xs font-bold mb-2 uppercase tracking-wider">{t('bom_qty')}</label>
                                          <input 
                                              type="number" 
                                              inputMode="numeric"
                                              value={bomQuantity} 
                                              onChange={(e) => setBomQuantity(e.target.value)} 
                                              className="w-full px-4 py-3 bg-gray-700 border border-gray-600 rounded-lg text-white font-mono placeholder-gray-500 placeholder:font-mono focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all text-lg" 
                                              placeholder="Napr. 500" 
                                          />
                                      </div>
                                      <div>
                                          <label className="block text-gray-400 text-xs font-bold mb-2 uppercase tracking-wider">{t('bom_select_wp')}</label>
                                          <select 
                                              value={bomSelectedWorkplace || ''} 
                                              onChange={(e) => setBomSelectedWorkplace(e.target.value)} 
                                              className="w-full px-4 py-3 bg-gray-700 border border-gray-600 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-lg"
                                          >
                                              <option value="" className="font-sans normal-case">{t('workplace_placeholder')}</option>
                                              {workplaces.map(wp => <option key={wp.id} value={wp.value}>{wp.value}</option>)}
                                          </select>
                                      </div>

                                      <button 
                                          onClick={handleCalculateBOM} 
                                          className="w-full bg-teal-600 hover:bg-teal-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-teal-900/20 transform transition-all active:scale-95 flex items-center justify-center gap-2"
                                      >
                                          <ActivityIcon className="h-5 w-5" />
                                          {t('bom_calc_btn')}
                                      </button>

                                      {bomParentQuery && bomResults.length === 0 && (
                                          <button 
                                              onClick={handleRequestNewBOM}
                                              disabled={bomRequestStatus !== 'idle'}
                                              className={`w-full py-3 rounded-xl border text-sm font-bold transition-all ${
                                                  bomRequestStatus === 'success' ? 'bg-green-600 border-green-500 text-white' : 
                                                  bomRequestStatus === 'loading' ? 'bg-gray-700 border-gray-600 text-gray-400 animate-pulse' :
                                                  'bg-gray-800 border-gray-600 text-gray-300 hover:bg-gray-700'
                                              }`}
                                          >
                                              {bomRequestStatus === 'loading' ? '...' : bomRequestStatus === 'success' ? t('bom_req_success') : t('bom_request_btn')}
                                          </button>
                                      )}
                                  </div>
                              </div>

                              {bomResults.length > 0 && (
                                  <div className="grid grid-cols-2 gap-4">
                                      <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                                          <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'Komponenty' : 'Components'}</p>
                                          <p className="text-2xl font-black text-white">{bomResults.length}</p>
                                      </div>
                                      <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                                          <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'Zostáva' : 'Remaining'}</p>
                                          <p className="text-2xl font-black text-orange-400">{bomResults.length - clickedBOMTasks.size}</p>
                                      </div>
                                  </div>
                              )}
                          </div>

                          <div className="lg:col-span-8">
                              {bomResults.length > 0 ? (
                                  <div className="bg-gray-800 rounded-2xl shadow-xl border border-gray-700 overflow-hidden flex flex-col h-full">
                                      <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/30">
                                          <div>
                                              <h3 className="text-xl font-bold text-white font-mono uppercase">
                                                  {displayedBomParent}
                                              </h3>
                                              <p className="text-sm text-gray-500">
                                                  {t('bom_results')} <span className="text-teal-400 font-bold">{displayedBomQuantity} ks</span>
                                              </p>
                                          </div>
                                          <button 
                                              onClick={() => handleCreateAllBOMTasks(bomResults)}
                                              className="bg-sky-600 hover:bg-sky-500 text-white px-5 py-2.5 rounded-xl text-sm font-bold shadow-lg transition-all active:scale-95 flex items-center gap-2"
                                          >
                                              🚀 {language === 'sk' ? 'Odoslať Všetko' : 'Send All'}
                                          </button>
                                      </div>

                                      <div className="overflow-x-auto flex-grow custom-scrollbar">
                                          <table className="w-full text-left">
                                              <thead className="bg-gray-900/50 text-gray-400 text-[10px] font-bold uppercase tracking-widest border-b border-gray-700">
                                                  <tr>
                                                      <th className="py-4 px-6">{t('bom_child')}</th>
                                                      <th className="py-4 px-6 text-center">{language === 'sk' ? 'Spotreba/ks' : 'Usage/pc'}</th>
                                                      <th className="py-4 px-6 text-right">{t('bom_req_qty')}</th>
                                                      <th className="py-4 px-6 text-center">{language === 'sk' ? 'Akcia' : 'Action'}</th>
                                                  </tr>
                                              </thead>
                                              <tbody className="divide-y divide-gray-700/50">
                                                  {bomResults.map((res) => {
                                                      const isSent = clickedBOMTasks.has(res.childPart);
                                                      return (
                                                          <tr key={res.childPart} className={`transition-colors ${isSent ? 'bg-teal-500/5 opacity-60' : 'hover:bg-gray-700/30'}`}>
                                                              <td className="py-5 px-6">
                                                                  <p className={`font-mono font-bold ${isSent ? 'text-gray-500' : 'text-white'}`}>{res.childPart}</p>
                                                                  <p className="text-[10px] text-gray-500">Standard Component</p>
                                                              </td>
                                                              <td className="py-5 px-6 text-center text-gray-400 font-mono text-xs">
                                                                  {res.quantity}
                                                              </td>
                                                              <td className="py-5 px-6 text-right">
                                                                  <span className={`text-lg font-bold font-mono ${isSent ? 'text-gray-500' : 'text-teal-400'}`}>
                                                                      {res.requiredQty} <span className="text-xs font-normal">ks</span>
                                                                  </span>
                                                              </td>
                                                              <td className="py-5 px-6 text-center">
                                                                  <button 
                                                                      onClick={() => !isSent && handleCreateBOMTask(res.childPart, res.requiredQty)}
                                                                      disabled={isSent}
                                                                      className={`inline-flex items-center justify-center p-2 rounded-lg transition-all ${
                                                                          isSent ? 'bg-gray-700 text-teal-500' : 'bg-teal-600/20 text-teal-400 hover:bg-teal-600 hover:text-white'
                                                                      }`}
                                                                  >
                                                                      {isSent ? <CheckCircleIcon className="w-6 h-6" /> : <PlusIcon className="w-6 h-6" />}
                                                                  </button>
                                                              </td>
                                                          </tr>
                                                      );
                                                  })}
                                              </tbody>
                                          </table>
                                      </div>
                                  </div>
                              ) : (
                                  <div className="h-full flex flex-col items-center justify-center bg-gray-800/50 rounded-2xl border-2 border-dashed border-gray-700 p-12 text-center">
                                      <div className="w-20 h-20 bg-gray-700 rounded-full flex items-center justify-center mb-6">
                                          <SearchIcon className="w-10 h-10 text-gray-500" />
                                      </div>
                                      <h3 className="text-xl font-bold text-gray-400 mb-2">{language === 'sk' ? 'Žiadne dáta na zobrazenie' : 'No data to display'}</h3>
                                      <p className="text-gray-500 max-w-xs">{language === 'sk' ? 'Zadajte číslo výrobku a plánované množstvo pre výpočet potrebného materiálu.' : 'Enter product number and planned quantity to calculate required material.'}</p>
                                  </div>
                              )}
                          </div>

                      </div>
                  </div>
              </div>
          )}
           {activeTab === 'missing' && hasPermission('perm_tab_missing') && <MissingItemsTab tasks={tasks} onDeleteMissingItem={props.onDeleteMissingItem} hasPermission={hasPermission} />}
           {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && <InventoryTab currentUser={currentUser} tasks={tasks} onAddTask={onAddTask} onUpdateTask={onUpdateTask} onToggleTask={onToggleTask} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} parts={parts.map(p => p.value)} onRequestPart={props.onRequestPart} />}
           {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && <LogisticsCenterTab tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} />}
           {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && <PermissionsTab roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} onVerifyAdminPassword={onVerifyAdminPassword} />}
        </div>
      </div>

      {/* Audit Start Modal */}
      {auditStartTask && createPortal(
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setAuditStartTask(null)}>
              <div className="bg-gray-800 border-2 border-[#926a05] rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-bold text-white mb-6 text-center uppercase tracking-wide">{t('audit_start_title')}</h3>
                  <p className="text-gray-300 text-center mb-8">
                      {t('audit_start_desc', { part: (auditStartTask?.partNumber || '') as string })}
                  </p>
                  <div className="flex gap-3">
                      <button onClick={() => setAuditStartTask(null)} className="flex-1 py-4 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors uppercase text-xs">{t('btn_cancel')}</button>
                      <button onClick={handleConfirmStartAudit} className="flex-1 py-4 bg-[#926a05] hover:bg-[#a67c06] text-white rounded-lg font-bold transition-colors shadow-lg uppercase text-xs">
                          {language === 'sk' ? 'Potvrdiť začiatok' : 'Confirm Start'}
                      </button>
                  </div>
              </div>
          </div>,
          document.body
      )}

      {/* Audit Finish Modal */}
      {auditFinishTask && createPortal(
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setAuditFinishTask(null)}>
              <div className="bg-gray-800 border-2 border-[#926a05] rounded-xl shadow-2xl w-full max-w-lg p-6 relative" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-bold text-white mb-6 text-center uppercase tracking-wide">{t('audit_finish_title')}</h3>

                  <div className="mb-6">
                      <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('audit_finish_note')}</label>
                      <textarea 
                        value={auditNote}
                        onChange={(e) => setAuditNote(e.target.value)}
                        className="w-full bg-gray-700 border border-gray-600 rounded-lg text-white px-4 py-3 focus:outline-none focus:ring-2 focus:ring-[#926a05] h-32"
                        placeholder="..."
                        autoFocus
                      />
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-4">
                      <button 
                        onClick={() => handleConfirmFinishAudit('found')}
                        disabled={!auditNote.trim()}
                        className={`py-4 rounded-lg font-bold transition-all shadow-lg uppercase text-xs flex items-center justify-center gap-2 ${!auditNote.trim() ? 'bg-gray-700 text-gray-500 cursor-not-allowed' : 'bg-green-600 hover:bg-green-500 text-white'}`}
                      >
                          ✅ {t('audit_found_btn')}
                      </button>
                      <button 
                        onClick={() => handleConfirmFinishAudit('missing')}
                        disabled={!auditNote.trim()}
                        className={`py-4 rounded-lg font-bold transition-all shadow-lg uppercase text-xs flex items-center justify-center gap-2 ${!auditNote.trim() ? 'bg-gray-700 text-gray-500 cursor-not-allowed' : 'bg-red-600 hover:bg-red-500 text-white'}`}
                      >
                          ❌ {t('audit_missing_btn')}
                      </button>
                  </div>

                  <button onClick={() => setAuditFinishTask(null)} className="w-full py-3 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors uppercase text-[10px]">{t('btn_cancel')}</button>
              </div>
          </div>,
          document.body
      )}
    </div>
  );
};

export default PartSearchScreen;

import React, { useState, useEffect, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { UserData, DBItem, PartRequest, BreakSchedule, BOMItem, BOMRequest, Role, Permission, SystemConfig } from '../App';
import { useLanguage } from './LanguageContext';

interface SettingsTabProps {
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  users: UserData[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateUserRole: (username: string, newRole: 'ADMIN' | 'USER' | 'LEADER') => void;
  onDeleteUser: (username: string) => void;
  // DB Props
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (id: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  onDeleteMissingReason: (id: string) => void;
  // Logistics Ops
  logisticsOperations?: DBItem[];
  onAddLogisticsOperation?: (val: string, time?: number) => void;
  onDeleteLogisticsOperation?: (id: string) => void;
  // Requests
  partRequests: PartRequest[];
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  // Archive
  onArchiveTasks: () => Promise<{ success: boolean; count?: number; error?: string; message?: string }>;
  // Breaks
  breakSchedules: BreakSchedule[];
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  // BOM
  bomItems: BOMItem[]; 
  bomRequests: BOMRequest[]; 
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (id: string) => void;
  onDeleteAllBOMItems: () => void;
  onApproveBOMRequest: (req: BOMRequest) => void;
  onRejectBOMRequest: (id: string) => void;
  // Roles
  roles: Role[];
  permissions: Permission[]; 
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  // PWA
  installPrompt: any;
  onInstallApp: () => void;
  // System Config
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  dbLoadWarning?: boolean;
}

const EyeIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
    </svg>
);

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
    </svg>
);

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
    </svg>
);

const ExclamationIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
    </svg>
);

const SettingsTab: React.FC<SettingsTabProps> = ({ 
  currentUserRole,
  users, onAddUser, onUpdatePassword, onUpdateUserRole, onDeleteUser,
  parts, workplaces, missingReasons, onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
  onAddWorkplace, onBatchAddWorkplaces, onDeleteWorkplace, onDeleteAllWorkplaces,
  onAddMissingReason, onDeleteMissingReason,
  logisticsOperations = [], onAddLogisticsOperation, onDeleteLogisticsOperation,
  partRequests, onApprovePartRequest, onRejectPartRequest, onArchiveTasks,
  breakSchedules, onAddBreakSchedule, onDeleteBreakSchedule,
  bomItems, bomRequests, onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems, onApproveBOMRequest, onRejectBOMRequest,
  roles, permissions, onAddRole, onDeleteRole, onUpdatePermission,
  installPrompt, onInstallApp,
  systemConfig, onUpdateSystemConfig,
  dbLoadWarning
}) => {
  // User State
  const [newUser, setNewUser] = useState('');
  const [newPass, setNewPass] = useState('');
  const [newRole, setNewRole] = useState<'USER' | 'ADMIN' | 'LEADER'>('USER');
  const [userError, setUserError] = useState('');
  const [passwordInputs, setPasswordInputs] = useState<Record<string, string>>({});
  const [visiblePasswords, setVisiblePasswords] = useState<Record<string, boolean>>({});

  // DB State
  const [newPart, setNewPart] = useState('');
  const [newPartDesc, setNewPartDesc] = useState('');
  const [bulkParts, setBulkParts] = useState('');
  const [partSearch, setPartSearch] = useState('');

  const [newWorkplace, setNewWorkplace] = useState('');
  const [newWorkplaceTime, setNewWorkplaceTime] = useState('');
  const [bulkWorkplaces, setBulkWorkplaces] = useState('');
  const [wpSearch, setWpSearch] = useState('');

  const [newMissingReason, setNewMissingReason] = useState('');
  const [reasonSearch, setReasonSearch] = useState('');

  const [newLogOp, setNewLogOp] = useState('');
  const [newLogOpTime, setNewLogOpTime] = useState('');
  const [logOpSearch, setLogOpSearch] = useState('');

  const [successMsg, setSuccessMsg] = useState('');
  const [isArchiving, setIsArchiving] = useState(false);

  // Break State
  const [newBreakStart, setNewBreakStart] = useState('');
  const [newBreakEnd, setNewBreakEnd] = useState('');

  // BOM State
  const [bomParent, setBomParent] = useState('');
  const [bomChild, setBomChild] = useState('');
  const [bomQty, setBomQty] = useState('');
  const [bomBulk, setBomBulk] = useState('');
  const [bomSearchQuery, setBomSearchQuery] = useState('');

  // Security State
  const [scheduleStart, setScheduleStart] = useState(systemConfig.maintenanceStart || '');
  const [scheduleEnd, setScheduleEnd] = useState(systemConfig.maintenanceEnd || '');
  const [newIp, setNewIp] = useState('');
  const [myIp, setMyIp] = useState('');

  // Confirmation Modal State
  const [confirmModal, setConfirmModal] = useState<{
      isOpen: boolean;
      title: string;
      message: string | React.ReactNode;
      onConfirm: () => void;
  }>({
      isOpen: false,
      title: '',
      message: '',
      onConfirm: () => {}
  });

  const { t } = useLanguage();

  const isAdmin = currentUserRole === 'ADMIN';
  const canManageDB = isAdmin;

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN') return true;
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  };

  const canManageLogOps = hasPermission('perm_manage_logistics_ops');

  useEffect(() => {
      if (isAdmin) {
          fetch('https://api.ipify.org?format=json')
            .then(res => res.json())
            .then(data => setMyIp(data.ip))
            .catch(() => setMyIp('Error fetching IP'));
      }
  }, [isAdmin]);

  const showSuccess = (msg: string) => {
    setSuccessMsg(msg);
    setTimeout(() => setSuccessMsg(''), 3000);
  };

  const uniqueUsers = useMemo(() => {
      const seen = new Set();
      return users.filter(user => {
          const upperName = user.username.toUpperCase();
          const isDuplicate = seen.has(upperName);
          seen.add(upperName);
          return !isDuplicate;
      });
  }, [users]);

  const openConfirmModal = (title: string, message: string, action: () => void) => {
      setConfirmModal({
          isOpen: true,
          title,
          message,
          onConfirm: action
      });
  };

  const closeConfirmModal = () => {
      setConfirmModal(prev => ({ ...prev, isOpen: false }));
  };

  const handleConfirmAction = () => {
      confirmModal.onConfirm();
      closeConfirmModal();
  };

  const filteredParts = parts.filter(p => 
      p.value.toLowerCase().includes(partSearch.toLowerCase()) || 
      (p.description && p.description.toLowerCase().includes(partSearch.toLowerCase()))
  );
  const filteredWorkplaces = workplaces.filter(w => w.value.toLowerCase().includes(wpSearch.toLowerCase()));
  const filteredReasons = missingReasons.filter(r => r.value.toLowerCase().includes(reasonSearch.toLowerCase()));
  const filteredLogOps = logisticsOperations.filter(op => op.value.toLowerCase().includes(logOpSearch.toLowerCase()));

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUser.trim() || !newPass.trim()) { setUserError(t('user_fill')); return; }
    if (users.some(u => u.username.toUpperCase() === newUser.toUpperCase())) { setUserError(t('user_exists')); return; }
    onAddUser({ username: newUser, password: newPass, role: newRole });
    setNewUser(''); setNewPass(''); setUserError('');
    showSuccess(t('user_added_success', { username: newUser }));
  };

  const handleSavePassword = (username: string) => {
    const pass = passwordInputs[username];
    if (!pass?.trim()) return;
    onUpdatePassword(username, pass);
    setPasswordInputs(prev => ({ ...prev, [username]: '' }));
    showSuccess(t('password_changed_success', { username }));
  };

  const togglePasswordVisibility = (username: string) => {
      setVisiblePasswords(prev => ({ ...prev, [username]: !prev[username] }));
  };

  const handleDeleteUserClick = (username: string) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_user', { name: username }),
          () => onDeleteUser(username)
      );
  };

  const handleAddSinglePart = (e: React.FormEvent) => {
    e.preventDefault();
    if(newPart.trim()) {
      onAddPart(newPart.trim(), newPartDesc.trim());
      setNewPart('');
      setNewPartDesc('');
      showSuccess(t('part_added_success'));
    }
  };

  const handleBulkAddParts = () => {
    const lines = bulkParts.split('\n').map(l => l.trim()).filter(l => l !== '');
    if (lines.length > 0) {
      onBatchAddParts(lines);
      setBulkParts('');
      showSuccess(t('parts_bulk_added_success', { count: lines.length }));
    }
  };

  const handleDeletePartClick = (item: DBItem) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_part', { name: item.value }),
          () => onDeletePart(item.id)
      );
  };

  const handleDeleteAllPartsConfirm = () => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('delete_all_parts_confirm'),
          () => {
              onDeleteAllParts();
              showSuccess(t('all_parts_deleted_success'));
          }
      );
  };

  const handleAddSingleWP = (e: React.FormEvent) => {
    e.preventDefault();
    if(newWorkplace.trim()) {
      const time = parseInt(newWorkplaceTime, 10);
      onAddWorkplace(newWorkplace.trim(), isNaN(time) ? 0 : time);
      setNewWorkplace('');
      setNewWorkplaceTime('');
      showSuccess(t('wp_added_success'));
    }
  };

  const handleBulkAddWP = () => {
    const lines = bulkWorkplaces.split('\n').map(l => l.trim()).filter(l => l !== '');
    if (lines.length > 0) {
      onBatchAddWorkplaces(lines);
      setBulkWorkplaces('');
      showSuccess(t('wp_bulk_added_success', { count: lines.length }));
    }
  };

  const handleDeleteWorkplaceClick = (item: DBItem) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_wp', { name: item.value }),
          () => onDeleteWorkplace(item.id)
      );
  };

  const handleDeleteAllWPConfirm = () => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('delete_all_workplaces_confirm'),
          () => {
              onDeleteAllWorkplaces();
              showSuccess(t('all_workplaces_deleted_success'));
          }
      );
  };

  const handleAddReason = (e: React.FormEvent) => {
      e.preventDefault();
      if(newMissingReason.trim()) {
          onAddMissingReason(newMissingReason.trim());
          setNewMissingReason('');
          showSuccess(t('reason_added_success'));
      }
  };

  const handleDeleteReasonClick = (item: DBItem) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_reason', { name: item.value }),
          () => onDeleteMissingReason(item.id)
      );
  };

  const handleAddLogOp = (e: React.FormEvent) => {
      e.preventDefault();
      if(newLogOp.trim() && onAddLogisticsOperation) {
          const time = parseInt(newLogOpTime, 10);
          onAddLogisticsOperation(newLogOp.trim(), isNaN(time) ? 0 : time);
          setNewLogOp('');
          setNewLogOpTime('');
          showSuccess(t('op_added_success'));
      }
  };

  const handleDeleteLogOpClick = (item: DBItem) => {
      if(onDeleteLogisticsOperation) {
          openConfirmModal(
              t('modal_confirm_title'),
              t('msg_delete_log_op', { name: item.value }),
              () => onDeleteLogisticsOperation(item.id)
          );
      }
  };

  const handleRunArchiving = async () => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('archive_confirm'),
          async () => {
              setIsArchiving(true);
              const result = await onArchiveTasks();
              setIsArchiving(false);

              if (result.success) {
                  if (result.count === 0 && result.message) {
                       alert(result.message);
                  } else {
                       alert(t('archive_success', { count: result.count || 0 }));
                  }
              } else {
                  alert(t('archive_error', { error: result.error || 'Unknown' }));
              }
          }
      );
  };

  const handleAddBreak = (e: React.FormEvent) => {
      e.preventDefault();
      if (newBreakStart && newBreakEnd) {
          onAddBreakSchedule(newBreakStart, newBreakEnd);
          setNewBreakStart('');
          setNewBreakEnd('');
          showSuccess(t('break_added_success'));
      }
  };

  const handleDeleteBreakClick = (id: string) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_break'),
          () => onDeleteBreakSchedule(id)
      );
  };

  const handleAddBOM = (e: React.FormEvent) => {
      e.preventDefault();
      if(bomParent && bomChild && bomQty) {
          onAddBOMItem(bomParent, bomChild, parseFloat(bomQty));
          setBomParent(''); setBomChild(''); setBomQty('');
          showSuccess(t('bom_added_success'));
      }
  };

  const handleBulkAddBOM = () => {
      const lines = bomBulk.split('\n').map(l => l.trim()).filter(l => l !== '');
      if (lines.length > 0) {
          onBatchAddBOMItems(lines);
          setBomBulk('');
          showSuccess(t('bom_bulk_added_success', { count: lines.length }));
      }
  }

  const handleDeleteBOMClick = (item: BOMItem) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_bom', { parent: item.parentPart, child: item.childPart }),
          () => onDeleteBOMItem(item.id)
      );
  };

  const handleDeleteAllBOMConfirm = () => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('delete_all_bom_confirm'),
          () => {
              onDeleteAllBOMItems();
              showSuccess(t('all_bom_deleted_success'));
          }
      );
  }

  const filteredBOMItems = bomItems.filter(item => 
      item.parentPart.toLowerCase().includes(bomSearchQuery.toLowerCase()) || 
      item.childPart.toLowerCase().includes(bomSearchQuery.toLowerCase())
  );

  const handleToggleMaintenance = () => {
      onUpdateSystemConfig({ maintenanceMode: !systemConfig.maintenanceMode });
  };

  const handleSaveMaintenanceSchedule = () => {
      if (scheduleStart && scheduleEnd) {
          onUpdateSystemConfig({ maintenanceStart: scheduleStart, maintenanceEnd: scheduleEnd });
          showSuccess('Schedule saved');
      }
  };

  const handleClearSchedule = () => {
      setScheduleStart('');
      setScheduleEnd('');
      onUpdateSystemConfig({ maintenanceStart: '', maintenanceEnd: '' });
  };

  const handleToggleIpCheck = () => {
      onUpdateSystemConfig({ ipCheckEnabled: !systemConfig.ipCheckEnabled });
  };

  const handleAddIp = () => {
      if (newIp.trim()) {
          const updated = [...(systemConfig.allowedIPs || []), newIp.trim()];
          onUpdateSystemConfig({ allowedIPs: updated });
          setNewIp('');
          showSuccess(t('sec_ip_added'));
      }
  };

  const handleRemoveIp = (ip: string) => {
      const updated = (systemConfig.allowedIPs || []).filter(i => i !== ip);
      onUpdateSystemConfig({ allowedIPs: updated });
      showSuccess(t('sec_ip_removed'));
  };

  // Industriálne Tailwind triedy pre refaktoring
  const industrialCardClass = "bg-[#1a1f2e] border border-gray-700/50 rounded-2xl p-6 shadow-2xl ring-1 ring-white/5 overflow-hidden relative";
  const subPanelClass = "bg-gray-900/40 rounded-xl p-5 border border-white/5 backdrop-blur-sm shadow-inner";
  const labelClass = "block text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mb-2";

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-8 animate-fade-in relative">
      {successMsg && <div className="fixed top-4 right-4 bg-green-600 text-white p-4 rounded-lg shadow-xl z-50 animate-bounce">{successMsg}</div>}

      {/* REQUESTS */}
      <div className="bg-gray-900 rounded-xl p-4 sm:p-6 shadow-lg border border-yellow-700/50">
          <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-2">
              <h2 className="text-xl font-bold text-yellow-400">{t('req_title')}</h2>
              {(partRequests.length > 0 || bomRequests.length > 0) && <span className="bg-yellow-500 text-black text-xs font-bold px-2 py-1 rounded-full animate-pulse">{partRequests.length + bomRequests.length} {t('req_waiting')}</span>}
          </div>
          {partRequests.length > 0 || bomRequests.length > 0 ? ( 
              <div className="space-y-3">
                  {partRequests.map(req => (
                      <div key={req.id} className="flex flex-col sm:flex-row sm:items-center justify-between bg-gray-800 p-4 rounded-lg border border-gray-700">
                          <div>
                            <p className="font-bold text-white text-lg font-mono">
                                <span className="text-gray-400 font-normal text-base mr-2">{t('req_type_part')}:</span>
                                {req.partNumber}
                            </p>
                            <p className="text-sm text-gray-400">{t('requested_by')}: {req.requestedBy} ({new Date(req.requestedAt).toLocaleString('sk-SK')})</p>
                          </div>
                          <div className="flex gap-2 mt-3 sm:mt-0">
                               <button onClick={() => onApprovePartRequest(req)} className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded text-sm font-bold">✓ {t('req_approve')}</button>
                               <button onClick={() => onRejectPartRequest(req.id)} className="bg-red-900 hover:bg-red-700 text-red-200 px-4 py-2 rounded text-sm font-bold">✕ {t('req_reject')}</button>
                          </div>
                      </div>
                  ))}
                  {bomRequests.map(req => (
                      <div key={req.id} className="flex flex-col sm:flex-row sm:items-center justify-between bg-gray-800 p-4 rounded-lg border border-gray-700">
                          <div>
                            <p className="font-bold text-white text-lg font-mono">
                                <span className="text-gray-400 font-normal text-base mr-2">{t('req_type_bom')}:</span>
                                {req.parentPart}
                            </p>
                            <p className="text-sm text-gray-400">{t('requested_by')}: {req.requestedBy} ({new Date(req.requestedAt).toLocaleString('sk-SK')})</p>
                          </div>
                          <div className="flex gap-2 mt-3 sm:mt-0">
                               <button onClick={() => onApproveBOMRequest(req)} className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded text-sm font-bold">✓ {t('req_approve')}</button>
                               <button onClick={() => onRejectBOMRequest(req.id)} className="bg-red-900 hover:bg-red-700 text-red-200 px-4 py-2 rounded text-sm font-bold">✕ {t('req_reject')}</button>
                          </div>
                      </div>
                  ))}
              </div>
          ) : <p className="text-gray-500 italic text-center py-4">{t('no_requests')}</p>}
      </div>

      {/* 1. USERS */}
      <div className="bg-gray-900 rounded-xl p-4 sm:p-6 shadow-lg border border-gray-700">
        <h2 className="text-xl font-bold text-teal-400 mb-6 border-b border-gray-700 pb-2">{t('sect_users_manage')}</h2>
        <div className="space-y-4 mb-8">
          {uniqueUsers.map((user) => (
              <div key={user.id || user.username} className="flex flex-col sm:flex-row sm:items-center justify-between bg-gray-800 p-4 rounded-lg gap-4">
                <div className="flex items-center gap-3 min-w-[150px]">
                  <div className={`w-3 h-3 rounded-full ${user.role === 'ADMIN' ? 'bg-red-500' : 'bg-teal-500'}`}></div>
                  <div>
                    <div className="flex items-center gap-2">
                        <p className="font-bold text-white">{user.username}</p>
                        {isAdmin && (
                            <button onClick={() => togglePasswordVisibility(user.username)} className="text-gray-500 hover:text-white" title={t('user_show_pass')}><EyeIcon className="w-4 h-4" /></button>
                        )}
                    </div>
                    {visiblePasswords[user.username] && isAdmin && <p className="text-xs text-yellow-400 font-mono mt-1">{user.password}</p>}
                    {isAdmin && user.username !== 'ADMIN' ? ( 
                       <select value={user.role} onChange={(e) => onUpdateUserRole(user.username, e.target.value as any)} className="mt-1 text-xs bg-gray-700 text-white border border-gray-600 rounded">
                           {roles.map(r => <option key={r.id} value={r.name}>{r.name}</option>)}
                       </select>
                    ) : <p className="text-xs text-gray-500">{user.role}</p>}
                  </div>
                </div>
                {(isAdmin) && (
                  <div className="flex flex-1 gap-2 items-center">
                    <input type="text" placeholder={t('new_password_placeholder')} value={passwordInputs[user.username] || ''} onChange={(e) => setPasswordInputs(p => ({ ...p, [user.username]: e.target.value }))} className="flex-1 min-w-0 bg-gray-700 border border-gray-600 rounded px-3 py-2 text-sm text-white" />
                    <button onClick={() => handleSavePassword(user.username)} className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded text-sm font-semibold whitespace-nowrap">{t('btn_save')}</button>
                    {(isAdmin && user.username !== 'ADMIN') && <button onClick={() => handleDeleteUserClick(user.username)} className="bg-red-900 hover:bg-red-700 text-red-100 px-3 py-2 rounded text-sm">X</button>}
                  </div>
                )}
              </div>
          ))}
        </div>
        <form onSubmit={handleAddUser} className="bg-gray-800 p-4 rounded-lg">
          <div className="grid grid-cols-1 sm:grid-cols-4 gap-4 items-end">
            <div><input value={newUser} onChange={e => setNewUser(e.target.value)} className="w-full bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white" placeholder={t('user_name')} /></div>
            <div><input value={newPass} onChange={e => setNewPass(e.target.value)} className="w-full bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white" placeholder={t('user_pass')} /></div>
            <div>
              <select value={newRole} onChange={e => setNewRole(e.target.value as any)} className="w-full bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white">
                {roles.map(r => <option key={r.id} value={r.name}>{r.name}</option>)}
              </select>
            </div>
            <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded font-semibold">{t('user_add_btn')}</button>
          </div>
          {userError && <p className="text-red-400 text-sm mt-2">{userError}</p>}
        </form>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* 2. PARTS */}
        <div className="bg-gray-900 rounded-xl p-4 sm:p-6 shadow-lg border border-gray-700 flex flex-col h-full">
          <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-2">
              <h2 className="text-xl font-bold text-teal-400">{t('sect_parts')}</h2>
              {canManageDB && parts.length > 0 && <button onClick={handleDeleteAllPartsConfirm} className="text-xs bg-red-900 hover:bg-red-800 text-red-100 px-3 py-1 rounded">{t('delete_all')}</button>}
          </div>
          <div className="mb-2 relative"><SearchIcon className="absolute top-2 left-2 w-4 h-4 text-gray-500"/><input value={partSearch} onChange={e=>setPartSearch(e.target.value)} className="w-full pl-8 pr-2 py-1 bg-gray-800 border border-gray-600 rounded text-sm text-white" placeholder={t('search_db_placeholder')} /></div>
          <div className="flex-1 overflow-y-auto max-h-60 bg-gray-800 rounded mb-4 p-2 space-y-1 custom-scrollbar">
            {filteredParts.map(item => (
              <div key={item.id} className="flex justify-between items-center bg-gray-700 px-3 py-1 rounded hover:bg-gray-600">
                <span className="text-sm font-mono">
                    {item.value} 
                    {item.description && <span className="text-gray-400 ml-2 italic">- {item.description}</span>}
                </span>
                {canManageDB && <button onClick={() => handleDeletePartClick(item)} className="text-red-400 hover:text-red-200">×</button>}
              </div>
            ))}
