      {successMsg && <div className="fixed top-4 right-4 bg-green-600 text-white p-4 rounded-lg shadow-xl z-50 animate-bounce">{successMsg}</div>}

      {/* REQUESTS */}
      <div className="bg-gray-900 rounded-xl p-4 sm:p-6 shadow-lg border border-yellow-700/50">
          <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-2">
              <h2 className="text-xl font-bold text-yellow-400">{t('req_title')}</h2>
              {(partRequests.length > 0 || bomRequests.length > 0) && <span className="bg-yellow-500 text-black text-xs font-bold px-2 py-1 rounded-full animate-pulse">{partRequests.length + bomRequests.length} {t('req_waiting')}</span>}
          </div>
          {partRequests.length > 0 || bomRequests.length > 0 ? ( 
              <div className="space-y-3">
                  {partRequests.map(req => (
                      <div key={req.id} className="flex flex-col sm:flex-row sm:items-center justify-between bg-gray-800 p-4 rounded-lg border border-gray-700">
                          <div>
                            <p className="font-bold text-white text-lg font-mono">
                                <span className="text-gray-400 font-normal text-base mr-2">{t('req_type_part')}:</span>
                                {req.partNumber}
                            </p>
                            <p className="text-sm text-gray-400">{t('requested_by')}: {req.requestedBy} ({new Date(req.requestedAt).toLocaleString('sk-SK')})</p>
                          </div>
                          <div className="flex gap-2 mt-3 sm:mt-0">
                               <button onClick={() => onApprovePartRequest(req)} className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded text-sm font-bold transition-all active:scale-95">✓ {t('req_approve')}</button>
                               <button onClick={() => onRejectPartRequest(req.id)} className="bg-red-900 hover:bg-red-700 text-red-200 px-4 py-2 rounded text-sm font-bold transition-all active:scale-95">✕ {t('req_reject')}</button>
                          </div>
                      </div>
                  ))}
                  {bomRequests.map(req => (
                      <div key={req.id} className="flex flex-col sm:flex-row sm:items-center justify-between bg-gray-800 p-4 rounded-lg border border-gray-700">
                          <div>
                            <p className="font-bold text-white text-lg font-mono">
                                <span className="text-gray-400 font-normal text-base mr-2">{t('req_type_bom')}:</span>
                                {req.parentPart}
                            </p>
                            <p className="text-sm text-gray-400">{t('requested_by')}: {req.requestedBy} ({new Date(req.requestedAt).toLocaleString('sk-SK')})</p>
                          </div>
                          <div className="flex gap-2 mt-3 sm:mt-0">
                               <button onClick={() => onApproveBOMRequest(req)} className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded text-sm font-bold transition-all active:scale-95">✓ {t('req_approve')}</button>
                               <button onClick={() => onRejectBOMRequest(req.id)} className="bg-red-900 hover:bg-red-700 text-red-200 px-4 py-2 rounded text-sm font-bold transition-all active:scale-95">✕ {t('req_reject')}</button>
                          </div>
                      </div>
                  ))}
              </div>
          ) : <p className="text-gray-500 italic text-center py-4">{t('no_requests')}</p>}
      </div>

      {/* 1. USERS - MODERN ENTERPRISE REDESIGN */}
      <div className={`${industrialCardClass} border-slate-700/50`}>
        <div className="flex items-center gap-4 mb-8 border-b border-white/5 pb-6">
            <div className="p-3 bg-teal-500/10 rounded-xl border border-teal-500/20 shadow-[0_0_15px_rgba(20,184,166,0.1)]">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-teal-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
                </svg>
            </div>
            <div>
                <h2 className="text-2xl font-black text-white uppercase tracking-tighter leading-none">{t('sect_users_manage')}</h2>
                <p className="text-slate-500 text-xs mt-1 font-bold">SYSTEM ACCESS CONTROL</p>
            </div>
        </div>

        <div className="space-y-3 mb-10">
          {uniqueUsers.map((user) => (
              <div key={user.id || user.username} className="group flex flex-col sm:flex-row sm:items-center justify-between bg-slate-900/40 border border-white/5 p-4 rounded-xl gap-4 hover:bg-slate-800/30 transition-all duration-300">
                <div className="flex items-center gap-4 min-w-[200px]">
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-sm border shadow-inner ${user.role === 'ADMIN' ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-teal-500/10 text-teal-500 border-teal-500/20'}`}>
                    {user.username.charAt(0).toUpperCase()}
                  </div>
                  <div>
                    <div className="flex items-center gap-2">
                        <p className="font-black text-white tracking-wide">{user.username}</p>
                        {isAdmin && (
                            <button onClick={() => togglePasswordVisibility(user.username)} className="text-slate-600 hover:text-white transition-colors" title={t('user_show_pass')}><EyeIcon className="w-3.5 h-3.5" /></button>
                        )}
                    </div>
                    <div className="flex items-center gap-2 mt-1">
                        {isAdmin && user.username !== 'ADMIN' ? ( 
                           <select 
                            value={user.role} 
                            onChange={(e) => onUpdateUserRole(user.username, e.target.value as any)} 
                            className="bg-slate-800 text-[10px] font-black text-slate-400 border border-slate-700 rounded px-1.5 py-0.5 outline-none focus:ring-1 focus:ring-teal-500/30 uppercase tracking-tighter"
                           >
                               {roles.map(r => <option key={r.id} value={r.name}>{r.name}</option>)}
                           </select>
                        ) : <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{user.role}</p>}
                        {visiblePasswords[user.username] && isAdmin && <span className="text-[10px] text-yellow-500/80 font-mono bg-yellow-500/5 px-1.5 rounded border border-yellow-500/20">{user.password}</span>}
                    </div>
                  </div>
                </div>

                {(isAdmin) && (
                  <div className="flex flex-1 gap-3 items-center">
                    <div className="relative flex-1 group/input">
                        <input 
                            type="text" 
                            placeholder={t('new_password_placeholder')} 
                            value={passwordInputs[user.username] || ''} 
                            onChange={(e) => setPasswordInputs(p => ({ ...p, [user.username]: e.target.value }))} 
                            className="w-full bg-slate-800/80 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white focus:ring-2 focus:ring-teal-500/30 outline-none transition-all" 
