                            onClick={() => handleDeleteUserClick(user.username)} 
                            className="p-2.5 bg-red-900/5 text-slate-600 hover:text-red-500 border border-transparent hover:border-red-900/20 rounded-lg transition-all active:scale-95 opacity-40 group-hover:opacity-100"
                            title={t('perm_btn_delete')}
                        >
                            <TrashIcon className="w-4 h-4" />
                        </button>
