          </div>
          <div className="mb-2 relative"><SearchIcon className="absolute top-2 left-2 w-4 h-4 text-gray-500"/><input value={partSearch} onChange={e=>setPartSearch(e.target.value)} className="w-full pl-8 pr-2 py-1 bg-gray-800 border border-gray-600 rounded text-sm text-white focus:ring-1 focus:ring-teal-500 outline-none" placeholder={t('search_db_placeholder')} /></div>
