                    <input value={newPartDesc} onChange={e => setNewPartDesc(e.target.value)} placeholder={t('part_desc_placeholder')} className="flex-1 bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white text-sm focus:ring-2 focus:ring-teal-500/30 outline-none" />
