                          onClick={handleToggleMaintenance}
                          className={`w-full sm:w-auto px-8 py-4 rounded-xl font-black text-sm transition-all duration-300 transform active:scale-95 shadow-lg ${
                              systemConfig.maintenanceMode 
                              ? 'bg-red-600 text-white border border-red-400 shadow-red-900/40' 
                              : 'bg-slate-800 text-slate-300 hover:bg-slate-700 border border-slate-700'
