                                                        <button onClick={() => handleDeleteBOMClick(item)} className="text-slate-600 hover:text-red-500 transition-colors p-2 opacity-0 group-hover:opacity-100">
                                                            <TrashIcon className="w-4 h-4" />
                                                        </button>
                                                    </td>
                                                </tr>
                                            )) : (
                                                <tr>
                                                    <td colSpan={4} className="py-20 text-center text-slate-600 font-bold italic uppercase tracking-widest text-xs">No records found</td>
                                                </tr>
                                            )}
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                            <div className="mt-4 flex justify-between items-center px-2">
                                <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Showing {filteredBOMItems.length} of {bomItems.length} records</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
          )}

          {/* TAB: SYSTEM (MAINTENANCE, BREAKS, PWA) */}
          {activeSubTab === 'system' && (
            <div className="space-y-6 animate-fade-in">
                {/* 6. DATA MAINTENANCE */}
                <div className="bg-slate-950/50 rounded-2xl p-6 shadow-2xl border-2 border-slate-800 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none group-hover:opacity-10 transition-opacity">
                        <svg xmlns="http://www.w3.org/2000/svg" className="w-32 h-32" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" />
                        </svg>
                    </div>
                    <div className="flex items-center gap-3 mb-4 border-b border-white/5 pb-3">
                        <div className="w-2 h-2 rounded-full bg-purple-500 shadow-[0_0_8px_rgba(168,85,247,0.8)]"></div>
                        <h2 className="text-xl font-black text-white uppercase tracking-tighter">{t('sect_maint')}</h2>
                    </div>
                    <p className="text-sm text-slate-400 mb-6 leading-relaxed font-medium">
                        {t('maint_desc')} <span className="text-slate-600 italic block mt-1 text-xs">Access restricted to system administrators.</span>
                    </p>
                    <div className="space-y-4">
                        <button 
                            onClick={handleRunArchiving} 
                            disabled={isArchiving}
                            className={`w-full py-4 px-6 rounded-xl font-black shadow-2xl transition-all flex items-center justify-center gap-3 transform active:scale-[0.98] ${isArchiving ? 'bg-slate-800 text-slate-600 cursor-not-allowed' : 'bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 text-white border-t border-white/20'}`}
                        >
                            {isArchiving ? (
                                <svg className="animate-spin h-5 w-5 text-slate-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                            ) : (
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" />
                                </svg>
                            )}
                            <span className="uppercase tracking-widest">{isArchiving ? t('archiving') : t('archive_btn')}</span>
                        </button>

                        <div className="pt-2">
                            <a 
                                href="https://console.firebase.google.com/" 
                                target="_blank" 
                                rel="noreferrer" 
                                className="group/link flex items-center justify-between p-4 bg-slate-900/80 border border-slate-700 rounded-xl hover:bg-slate-800 hover:border-slate-600 transition-all duration-300 shadow-inner"
                            >
                                <div className="flex items-center gap-3">
                                    <div className="p-2 bg-amber-500/10 rounded-lg group-hover/link:bg-amber-500/20 transition-colors">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="w-5 h-5 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10c0 2.21 3.582 4 8 4s8-1.79 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.79 8-4M4 7c0-2.21 3.582-4 8-4s8 1.79 8 4m0 5c0 2.21-3.582 4-8 4s-8-1.79-8-4" />
                                        </svg>
                                    </div>
                                    <span className="text-xs font-black text-slate-300 uppercase tracking-widest">{t('sect_maint_db_link')}</span>
                                </div>
                                <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4 text-slate-600 group-hover/link:text-slate-400 group-hover/link:translate-x-1 transition-all" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
                                </svg>
                            </a>
                        </div>
                    </div>
                </div>

                {/* 7. BREAK MANAGEMENT */}
                <div className="bg-slate-900/40 border border-slate-800 rounded-xl p-6 shadow-xl flex flex-col">
                    <div className="flex justify-between items-center mb-6 border-b border-slate-800 pb-4">
                        <h2 className="text-xl font-black text-teal-400 uppercase tracking-tight">{t('sect_breaks')}</h2>
                    </div>
                    <div className="space-y-2 mb-6 max-h-48 overflow-y-auto custom-scrollbar pr-2">
                        {breakSchedules.length > 0 ? breakSchedules.map(b => (
                            <div key={b.id} className="flex justify-between items-center bg-slate-800/60 px-4 py-3 rounded-xl border border-white/5 hover:border-teal-500/30 transition-all group shadow-sm">
                                <div className="flex items-center gap-3">
                                    <div className="w-1.5 h-1.5 rounded-full bg-teal-500 shadow-[0_0_5px_teal]"></div>
                                    <span className="text-sm font-mono font-black text-slate-200 tracking-wider">{b.start} — {b.end}</span>
                                </div>
                                <button onClick={() => handleDeleteBreakClick(b.id)} className="text-slate-600 hover:text-red-500 transition-colors p-1 group-hover:scale-110">
                                    <TrashIcon className="w-4 h-4" />
                                </button>
                            </div>
                        )) : (
                            <div className="text-center py-10 border-2 border-dashed border-slate-800 rounded-2xl bg-slate-900/20">
                                <span className="text-[10px] text-slate-600 font-black uppercase tracking-[0.3em]">No Breaks Scheduled</span>
                            </div>
                        )}
                    </div>
                    <form onSubmit={handleAddBreak} className="mt-auto bg-slate-900/50 p-4 rounded-2xl border border-white/5 shadow-inner">
                        <div className="flex items-center gap-3">
                            <div className="flex-1 space-y-1">
                                <input 
                                    type="time" 
                                    value={newBreakStart} 
                                    onChange={e => setNewBreakStart(e.target.value)} 
                                    required 
                                    className="w-full bg-slate-800 border border-slate-700 rounded-xl px-3 py-2 text-white text-sm focus:ring-2 focus:ring-teal-500/30 outline-none transition-all font-mono" 
                                />
                            </div>
                            <span className="text-slate-600 font-black">—</span>
                            <div className="flex-1 space-y-1">
                                <input 
                                    type="time" 
                                    value={newBreakEnd} 
                                    onChange={e => setNewBreakEnd(e.target.value)} 
                                    required 
                                    className="w-full bg-slate-800 border border-slate-700 rounded-xl px-3 py-2 text-white text-sm focus:ring-2 focus:ring-teal-500/30 outline-none transition-all font-mono" 
                                />
                            </div>
                            <button type="submit" className="bg-teal-600 hover:bg-teal-500 text-white font-black px-5 py-2.5 rounded-xl text-[10px] uppercase tracking-widest shadow-lg transition-all active:scale-95">
                                Add
                            </button>
                        </div>
                    </form>
                </div>

                {/* 8. PWA INSTALLATION */}
                <div className="bg-gray-900 rounded-xl p-4 sm:p-6 shadow-lg border border-gray-700">
                    <h2 className="text-xl font-bold text-teal-400 mb-6 border-b border-gray-700 pb-2">{t('sect_pwa')}</h2>
                    <p className="text-sm text-gray-400 mb-6">{t('pwa_desc')}</p>
                    <button 
                        onClick={onInstallApp}
                        disabled={!installPrompt}
                        className={`w-full py-4 rounded-xl font-black transition-all shadow-xl flex items-center justify-center gap-3 ${!installPrompt ? 'bg-gray-800 text-gray-600 border-2 border-gray-700 cursor-not-allowed opacity-50' : 'bg-blue-600 hover:bg-blue-500 text-white border-2 border-blue-400 active:scale-95'}`}
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                        {installPrompt ? t('pwa_install_btn') : t('pwa_installed')}
                    </button>
                </div>
            </div>
          )}

          {/* TAB: SECURITY & SYSTEM CONFIG */}
          {activeSubTab === 'security' && (
            <div className="animate-fade-in">
                <div className={`${industrialCardClass} md:col-span-2 shadow-teal-900/10 border-slate-700/50`}>
                    <div className="flex items-center gap-4 mb-8 border-b border-white/5 pb-6">
                        <div className="p-3 bg-teal-500/10 rounded-xl border border-teal-500/20 shadow-[0_0_15px_rgba(20,184,166,0.1)]">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-teal-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                            </svg>
                        </div>
                        <div>
                            <h2 className="text-2xl font-black text-white uppercase tracking-tighter leading-none">{t('sect_security')}</h2>
                            <p className="text-slate-500 text-xs mt-1 font-bold">{isAdmin ? "SYSTEM ADMINISTRATOR MODE" : "RESTRICTED ACCESS"}</p>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 relative z-10">
                        <div className="space-y-6">
                            <div className={`${subPanelClass} ${systemConfig.maintenanceMode ? 'ring-2 ring-red-500/40 bg-red-900/5' : ''} transition-all duration-500`}>
                                <div className="flex justify-between items-start mb-2">
                                    <h3 className="text-base font-black text-white uppercase">{t('sec_maint_mode')}</h3>
                                    <div className={`px-2 py-0.5 rounded text-[9px] font-black uppercase tracking-widest flex items-center gap-1.5 ${systemConfig.maintenanceMode ? 'bg-red-500/20 text-red-500 animate-pulse' : 'bg-slate-800 text-slate-500'}`}>
                                        <div className={`w-1.5 h-1.5 rounded-full ${systemConfig.maintenanceMode ? 'bg-red-500 shadow-[0_0_5px_red]' : 'bg-slate-600'}`}></div>
                                        {systemConfig.maintenanceMode ? t('sec_maint_active') : t('sec_maint_inactive')}
                                    </div>
                                </div>
                                <p className="text-xs text-slate-500 mb-6 leading-relaxed max-w-sm">{t('sec_maint_desc')}</p>

                                <button 
                                    onClick={handleToggleMaintenance}
                                    className={`w-full sm:w-auto px-8 py-4 rounded-xl font-black text-sm transition-all duration-300 transform active:scale-95 shadow-lg ${
                                        systemConfig.maintenanceMode 
                                        ? 'bg-red-600 text-white border border-red-400 shadow-red-900/40' 
                                        : 'bg-slate-800 text-slate-300 hover:bg-slate-700 border border-slate-700'
                                    }`}
                                >
                                    {systemConfig.maintenanceMode ? t('sec_btn_disable') : t('sec_btn_enable')}
                                </button>
                            </div>

                            <div className={subPanelClass}>
                                <h4 className={`${labelClass} text-teal-500/50`}>{t('sec_schedule_title')}</h4>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                                    <div className="space-y-1">
                                        <span className="text-[10px] text-slate-600 font-bold uppercase ml-1 tracking-wider">{t('sec_start')}</span>
                                        <input 
                                            type="datetime-local" 
                                            value={scheduleStart} 
                                            onChange={e=>setScheduleStart(e.target.value)} 
                                            className={`${inputModernClass} !py-2.5 h-12 bg-slate-900/80`} 
                                        />
                                    </div>
                                    <div className="space-y-1">
                                        <span className="text-[10px] text-slate-600 font-bold uppercase ml-1 tracking-wider">{t('sec_end')}</span>
                                        <input 
                                            type="datetime-local" 
                                            value={scheduleEnd} 
                                            onChange={e=>setScheduleEnd(e.target.value)} 
                                            className={`${inputModernClass} !py-2.5 h-12 bg-slate-900/80`} 
                                        />
                                    </div>
                                </div>
                                <div className="flex gap-3">
                                    <button onClick={handleSaveMaintenanceSchedule} className="flex-1 bg-teal-600 hover:bg-teal-500 text-white text-xs font-black py-3 rounded-xl transition-all shadow-lg active:scale-95 uppercase tracking-widest">{t('sec_btn_schedule')}</button>
                                    <button onClick={handleClearSchedule} className="px-5 bg-slate-800 hover:bg-slate-700 text-slate-400 text-xs font-black py-3 rounded-xl border border-slate-700 transition-all active:scale-95 uppercase tracking-widest">{t('sec_btn_clear_schedule')}</button>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-6">
                            <div className={subPanelClass}>
                                <div className="flex justify-between items-center mb-6">
                                    <div>
                                        <h3 className="text-base font-black text-white uppercase mb-1">{t('sec_ip_whitelist')}</h3>
                                        <p className="text-[10px] text-slate-500 font-bold leading-tight uppercase tracking-wider">{t('sec_ip_desc')}</p>
                                    </div>
                                    <button 
                                        onClick={handleToggleIpCheck}
                                        className={`text-[10px] font-black px-4 py-2 rounded-full border-2 transition-all active:scale-95 shadow-md ${
                                            systemConfig.ipCheckEnabled 
                                            ? 'bg-green-500/10 text-green-400 border-green-500/30' 
                                            : 'bg-slate-800 text-slate-500 border-slate-700'
                                        }`}
                                    >
                                        {systemConfig.ipCheckEnabled ? t('sec_ip_check_enabled') : t('sec_ip_check_disabled')}
                                    </button>
                                </div>

                                <div className="bg-black/30 p-4 rounded-xl border border-white/5 mb-6 flex justify-between items-center">
                                    <span className={`${labelClass} mb-0`}>{t('sec_my_ip')}</span>
                                    <span className="text-xs font-mono font-black text-teal-400 bg-teal-400/5 px-3 py-1 rounded-lg border border-teal-500/20 shadow-sm">{myIp}</span>
                                </div>

                                <div className="space-y-2 mb-6 max-h-48 overflow-y-auto custom-scrollbar pr-2">
                                    {(systemConfig.allowedIPs || []).length > 0 ? (
                                        (systemConfig.allowedIPs || []).map(ip => (
                                            <div key={ip} className="flex justify-between items-center bg-slate-900/60 px-4 py-3 rounded-xl border border-white/5 hover:border-teal-500/30 transition-all group shadow-sm">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-1.5 h-1.5 rounded-full bg-teal-500 shadow-[0_0_5px_teal] group-hover:animate-pulse"></div>
                                                    <span className="text-sm font-mono font-bold text-slate-300">{ip}</span>
                                                </div>
                                                <button onClick={() => handleRemoveIp(ip)} className="text-slate-600 hover:text-red-500 transition-colors p-1 group-hover:scale-110">
                                                    <TrashIcon className="w-4 h-4" />
                                                </button>
                                            </div>
                                        ))
                                    ) : (
                                        <div className="text-center py-10 border-2 border-dashed border-slate-800 rounded-2xl bg-slate-900/20">
                                            <span className="text-[10px] text-slate-600 font-black uppercase tracking-[0.3em]">No Restricted IPs</span>
                                        </div>
                                    )}
                                </div>

                                <div className="flex gap-2">
                                    <input 
                                        value={newIp} 
                                        onChange={e=>setNewIp(e.target.value)} 
                                        placeholder={t('sec_ip_placeholder')} 
                                        className={`${inputModernClass} !py-3 bg-slate-900/80 border-slate-800 placeholder:text-slate-700`} 
                                    />
                                    <button 
                                        onClick={handleAddIp} 
                                        className="bg-blue-600 hover:bg-blue-500 text-white px-6 rounded-xl transition-all shadow-lg active:scale-95 font-black text-xl border border-blue-400/30"
                                    >
                                        +
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
          )}
      </div>

      {/* Confirmation Modal Portal */}
      {confirmModal.isOpen && createPortal(
           <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={closeConfirmModal}>
               <div className="bg-[#1a1f2e] border-2 border-red-900/50 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                   <div className="text-center mb-8">
                       <div className="w-20 h-20 bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-6 border border-red-500/30 shadow-[0_0_20px_rgba(220,38,38,0.1)]">
                           <ExclamationIcon className="w-10 h-10 text-red-500" />
                       </div>
                       <h3 className="text-2xl font-black text-white mb-2 uppercase tracking-tighter">{confirmModal.title}</h3>
                       <div className="text-slate-400 text-sm font-medium leading-relaxed">{confirmModal.message}</div>
                   </div>
                   <div className="flex gap-4">
                       <button onClick={closeConfirmModal} className="flex-1 py-4 bg-slate-800 text-slate-300 rounded-xl hover:bg-slate-700 font-black transition-all active:scale-95 uppercase tracking-widest text-xs">{t('btn_cancel')}</button>
                       <button onClick={handleConfirmAction} className="flex-1 py-4 bg-red-600 text-white rounded-xl hover:bg-red-500 font-black transition-all shadow-lg active:scale-95 flex items-center justify-center gap-3 uppercase tracking-widest text-xs border border-red-400/50">
                           <TrashIcon className="w-5 h-5" />
                           {t('btn_confirm_delete')}
                       </button>
                   </div>
               </div>
           </div>,
           document.body
       )}
    </div>
  );
};

export default SettingsTab;

import React, { useState, useEffect, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { UserData, DBItem, PartRequest, BreakSchedule, BOMItem, BOMRequest, Role, Permission, SystemConfig } from '../App';
import { useLanguage } from './LanguageContext';

interface SettingsTabProps {
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  users: UserData[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateUserRole: (username: string, newRole: 'ADMIN' | 'USER' | 'LEADER') => void;
  onDeleteUser: (username: string) => void;
  // DB Props
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (id: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  onDeleteMissingReason: (id: string) => void;
  // Logistics Ops
  logisticsOperations?: DBItem[];
  onAddLogisticsOperation?: (val: string, time?: number) => void;
  onDeleteLogisticsOperation?: (id: string) => void;
  // Requests
  partRequests: PartRequest[];
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  // Archive
  onArchiveTasks: () => Promise<{ success: boolean; count?: number; error?: string; message?: string }>;
  // Breaks
  breakSchedules: BreakSchedule[];
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  // BOM
  bomItems: BOMItem[]; 
  bomRequests: BOMRequest[]; 
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (id: string) => void;
  onDeleteAllBOMItems: () => void;
  onApproveBOMRequest: (req: BOMRequest) => void;
  onRejectBOMRequest: (id: string) => void;
  // Roles
  roles: Role[];
  permissions: Permission[]; 
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  // PWA
  installPrompt: any;
  onInstallApp: () => void;
  // System Config
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  dbLoadWarning?: boolean;
}

