                                                </div>
                                            </td>

                                            {/* DIEL & PRACOVISKO */}
                                            <td className="py-4 px-6">
                                                <div className="flex flex-col gap-1">
                                                    <span className="text-[11px] font-black font-mono text-white bg-slate-800 px-3 py-1 rounded-md border border-slate-700 w-fit shadow-sm uppercase">
                                                        {item.partNumber}
                                                    </span>
                                                    <span className="text-[10px] font-black text-teal-400 uppercase tracking-wider">
                                                        {item.workplace}
                                                    </span>
                                                </div>
                                            </td>

                                            {/* DÔVOD */}
                                            <td className="py-4 px-6">
                                                <span className="text-sm font-black text-amber-500 tracking-tight leading-tight block">
                                                    {item.missingReason}
                                                </span>
                                            </td>

                                            {/* NAHLÁSIL */}
                                            <td className="py-4 px-6">
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-bold text-slate-200">{item.missingReportedBy || '-'}</span>
                                                    <span className="text-[10px] text-slate-500 font-medium">{formatDateShort(item.completedAt)}</span>
                                                </div>
                                            </td>

                                            {/* AGEING */}
                                            <td className="py-4 px-6">
                                                <div className="flex items-center gap-2">
                                                    <div className={`w-1.5 h-1.5 rounded-full ${getAgeingColor(reportTime).includes('red') ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.8)] animate-pulse' : 'bg-teal-500'}`}></div>
                                                    <span className={`text-[11px] font-black uppercase tracking-widest ${getAgeingColor(reportTime)}`}>
                                                        {formatAgeing(reportTime)}
                                                    </span>
                                                </div>
                                            </td>

                                            {/* AUDIT */}
                                            <td className="py-4 px-6">
                                                {it.auditedBy ? (
                                                    <div className="flex flex-col">
                                                        <span className="text-sm font-bold text-slate-300">{it.auditedBy}</span>
                                                        <span className="text-[10px] text-slate-500 font-medium">{formatDateShort(it.auditedAt)}</span>
                                                    </div>
                                                ) : (
                                                    <span className="text-[10px] text-slate-600 font-black uppercase tracking-widest italic opacity-40">Čaká na audit</span>
                                                )}
                                            </td>

                                            {/* VÝSLEDOK */}
                                            <td className="py-4 px-6">
                                                {it.auditResult ? (
                                                    <div className="flex flex-col gap-1">
                                                        <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest w-fit border ${it.auditResult === 'OK' ? 'bg-green-500/10 text-green-500 border-green-500/20' : 'bg-red-600/10 text-red-500 border-red-600/20'}`}>
                                                            {it.auditResult}
                                                        </span>
                                                        {it.auditNote && <span className="text-[10px] text-slate-400 italic font-medium leading-tight line-clamp-2" title={it.auditNote}>{it.auditNote}</span>}
                                                    </div>
                                                ) : (
                                                    <span className="text-[10px] text-slate-700 font-black uppercase">—</span>
                                                )}
                                            </td>

                                            {/* DELETE */}
                                            {hasPermission('perm_btn_delete') && (
                                                <td className="py-4 px-6 text-center">
                                                    <button onClick={() => handleDelete(item.id)} className="text-slate-700 hover:text-red-500 p-2 transition-all opacity-0 group-hover:opacity-100 hover:scale-110 active:scale-90">
                                                        <TrashIcon className="h-4.5 w-4.5" />
                                                    </button>
                                                </td>
                                            )}
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={hasPermission('perm_btn_delete') ? 8 : 7} className="py-32 text-center text-slate-600">
                                        <div className="flex flex-col items-center gap-5">
                                            <div className="p-6 bg-slate-900 rounded-full border border-slate-800 shadow-inner">
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 text-slate-800" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                            </div>
